  ('dietitian-moex-02600', 'dietitian', 'dietitian-moex-105-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', 'Taurine是參與脂質消化吸收的重要化合物，在大多數的哺乳類動物中，下列何種胺基酸經三個酵素反應 後可以合成taurine？', '["valine", "histidine", "threonine", "cysteine"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "dbdc7430cd09", "answer_pdf_sha1": "f7bdd424f961", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
